export interface CulturalEvent {
  id: string;
  title: string;
  category: string;
  date: string; // YYYY-MM-DD
  time: string; // HH:mm
  imageUrl: string;
  description?: string;
  location?: string;
  price?: number;
}

export enum EventCategory {
