import React, { useState } from 'react';
import { CulturalEvent } from '../types';
import { Save, RefreshCw, AlertTriangle, FileJson, Wand2 } from 'lucide-react';
import { generateEventDescription } from '../services/geminiService';

interface AdminPanelProps {
  currentEvents: CulturalEvent[];
  onUpdateEvents: (events: CulturalEvent[]) => void;
}

export const AdminPanel: React.FC<AdminPanelProps> = ({ currentEvents, onUpdateEvents }) => {
  const [jsonInput, setJsonInput] = useState<string>('');
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  // Initialize with current data
  React.useEffect(() => {
    setJsonInput(JSON.stringify(currentEvents, null, 2));
  }, [currentEvents]);

  const handleValidate = () => {
    try {
      const parsed = JSON.parse(jsonInput);
      if (!Array.isArray(parsed)) throw new Error("El formato debe ser un arreglo de eventos [].");
      setError(null);
      setSuccess("JSON válido. Listo para actualizar.");
      return parsed;
    } catch (e) {
      setError((e as Error).message);
      setSuccess(null);
      return null;
    }
  };

  const handleReplace = () => {
    const data = handleValidate();
    if (data) {
      if (window.confirm("¿Estás seguro de reemplazar TODA la base de datos actual con estos datos?")) {
        onUpdateEvents(data);
        setSuccess("Base de datos reemplazada exitosamente.");
      }
    }
  };

  const handleAppend = () => {
    const data = handleValidate();
    if (data) {
      onUpdateEvents([...currentEvents, ...data]);
      setSuccess(`Se añadieron ${data.length} eventos nuevos.`);
    }
  };

  const handleEnhanceWithAI = async () => {
    const data = handleValidate();
    if (!data) return;

    setIsProcessing(true);
    setSuccess(null);
    const updatedData = [...data];
    let changesCount = 0;

    try {
      for (let i = 0; i < updatedData.length; i++) {
        const ev = updatedData[i];
        if (!ev.description || ev.description.length < 10) {
          ev.description = await generateEventDescription(ev.title, ev.category);
          changesCount++;
        }
      }
      setJsonInput(JSON.stringify(updatedData, null, 2));
      setSuccess(`IA: Se generaron descripciones para ${changesCount} eventos.`);
    } catch (e) {
      setError("Error al conectar con la IA.");
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="bg-white rounded-xl shadow-lg p-6 animate-fade-in">
      <div className="flex items-center space-x-3 mb-6">
        <div className="bg-orange-100 p-3 rounded-full">
          <FileJson className="w-6 h-6 text-orange-600" />
        </div>
        <div>
          <h2 className="text-2xl font-bold text-gray-800">Gestor de Base de Datos</h2>
          <p className="text-gray-500 text-sm">Edita, reemplaza o añade eventos mediante JSON.</p>
        </div>
      </div>

      <div className="bg-blue-50 border-l-4 border-blue-500 p-4 mb-6">
        <div className="flex">
          <div className="flex-shrink-0">
            <AlertTriangle className="h-5 w-5 text-blue-500" />
          </div>
          <div className="ml-3">
            <p className="text-sm text-blue-700">
              Copia tus datos de eventos aquí. Asegúrate de que sigan la estructura: 
              <code> {`{ id, title, category, date, time, imageUrl }`}</code>
            </p>
          </div>
        </div>
      </div>

      <div className="relative">
        <textarea
          value={jsonInput}
          onChange={(e) => setJsonInput(e.target.value)}
          className="w-full h-96 p-4 bg-gray-900 text-green-400 font-mono text-sm rounded-lg border border-gray-700 focus:ring-2 focus:ring-indigo-500 focus:border-transparent scrollbar-thin"
          spellCheck={false}
        />
        <div className="absolute top-2 right-2 flex space-x-2">
           <button
             onClick={handleEnhanceWithAI}
             disabled={isProcessing}
             className="bg-indigo-600 hover:bg-indigo-700 text-white text-xs px-3 py-1 rounded flex items-center shadow-lg transition-colors disabled:opacity-50"
             title="Generar descripciones automáticas para eventos vacíos"
           >
             <Wand2 className={`w-3 h-3 mr-1 ${isProcessing ? 'animate-spin' : ''}`} />
             {isProcessing ? 'Generando...' : 'Completar con IA'}
           </button>
        </div>
      </div>

      {(error || success) && (
        <div className={`mt-4 p-3 rounded-md ${error ? 'bg-red-100 text-red-700' : 'bg-green-100 text-green-700'}`}>
          {error || success}
        </div>
      )}

      <div className="flex flex-col sm:flex-row gap-4 mt-6 pt-6 border-t border-gray-100">
        <button
          onClick={handleReplace}
          className="flex-1 flex items-center justify-center px-6 py-3 border border-transparent text-base font-medium rounded-md text-white bg-red-600 hover:bg-red-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-red-500 shadow-sm transition-all"
        >
          <RefreshCw className="w-5 h-5 mr-2" />
          Reemplazar Todo
        </button>
        <button
          onClick={handleAppend}
          className="flex-1 flex items-center justify-center px-6 py-3 border border-transparent text-base font-medium rounded-md text-white bg-green-600 hover:bg-green-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-green-500 shadow-sm transition-all"
        >
          <Save className="w-5 h-5 mr-2" />
          Añadir/Fusionar
        </button>
      </div>
    </div>
  );
};

import React from 'react';
import { CulturalEvent } from '../types';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend, BarChart, Bar, XAxis, YAxis, CartesianGrid } from 'recharts';

interface StatsProps {
  events: CulturalEvent[];
}

const COLORS = ['#6366f1', '#ec4899', '#10b981', '#f59e0b', '#8b5cf6', '#ef4444', '#3b82f6'];

export const Stats: React.FC<StatsProps> = ({ events }) => {

  const categoryData = React.useMemo(() => {
    const counts: Record<string, number> = {};
    events.forEach(e => {
      counts[e.category] = (counts[e.category] || 0) + 1;
    });
    return Object.entries(counts).map(([name, value]) => ({ name, value }));
  }, [events]);

  const dateData = React.useMemo(() => {
    const counts: Record<string, number> = {};
    events.forEach(e => {
      counts[e.date] = (counts[e.date] || 0) + 1;
    });
    // Sort by date
    return Object.entries(counts)
      .sort((a, b) => a[0].localeCompare(b[0]))
      .slice(0, 7) // Take first 7 days for readability
      .map(([name, value]) => ({ name, value }));
  }, [events]);

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
      <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
        <h3 className="text-lg font-bold text-gray-800 mb-4">Eventos por Categoría</h3>
        <div className="h-64">
          <ResponsiveContainer width="100%" height="100%">
            <PieChart>
              <Pie
                data={categoryData}
                cx="50%"
                cy="50%"
                labelLine={false}
                outerRadius={80}
                fill="#8884d8"
                dataKey="value"
              >
                {categoryData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                ))}
              </Pie>
              <Tooltip />
              <Legend />
            </PieChart>
          </ResponsiveContainer>
        </div>
      </div>

      <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
        <h3 className="text-lg font-bold text-gray-800 mb-4">Actividad Próxima (7 días)</h3>
        <div className="h-64">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={dateData}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} />
              <XAxis dataKey="name" tick={{fontSize: 12}} />
              <YAxis allowDecimals={false} />
              <Tooltip />
              <Bar dataKey="value" fill="#6366f1" radius={[4, 4, 0, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { CulturalEvent } from '../types';
import { generateEventRecommendations } from '../services/geminiService';
import { MessageCircle, X, Send, Sparkles, Loader2 } from 'lucide-react';

interface AIAssistantProps {
  events: CulturalEvent[];
}

interface Message {
  id: number;
  text: string;
  sender: 'user' | 'ai';
}

export const AIAssistant: React.FC<AIAssistantProps> = ({ events }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<Message[]>([
    { id: 1, text: "¡Hola! Soy tu guía cultural. ¿Buscas algo en específico para hoy?", sender: 'ai' }
  ]);
  const [inputValue, setInputValue] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!inputValue.trim()) return;

    const userMsg: Message = { id: Date.now(), text: inputValue, sender: 'user' };
    setMessages(prev => [...prev, userMsg]);
    setInputValue('');
    setIsLoading(true);

    const aiResponseText = await generateEventRecommendations(userMsg.text, events);

    const aiMsg: Message = { id: Date.now() + 1, text: aiResponseText, sender: 'ai' };
    setMessages(prev => [...prev, aiMsg]);
    setIsLoading(false);
  };

  return (
    <>
      {/* Floating Button */}
      <button
        onClick={() => setIsOpen(!isOpen)}
        className={`fixed bottom-6 right-6 z-50 p-4 rounded-full shadow-2xl transition-all duration-300 transform hover:scale-110 ${
          isOpen ? 'bg-red-500 rotate-90' : 'bg-gradient-to-r from-indigo-600 to-purple-600'
        }`}
      >
        {isOpen ? (
          <X className="w-6 h-6 text-white" />
        ) : (
          <Sparkles className="w-6 h-6 text-white animate-pulse" />
        )}
      </button>

      {/* Chat Window */}
      {isOpen && (
        <div className="fixed bottom-24 right-6 w-80 sm:w-96 h-[500px] bg-white rounded-2xl shadow-2xl border border-gray-200 flex flex-col z-50 animate-slide-up overflow-hidden">
          {/* Header */}
          <div className="bg-indigo-600 p-4 flex items-center justify-between">
            <div className="flex items-center space-x-2">
              <div className="w-8 h-8 bg-white/20 rounded-full flex items-center justify-center">
                <Sparkles className="w-4 h-4 text-white" />
              </div>
              <div>
                <h3 className="font-bold text-white text-sm">Asistente Cultural</h3>
                <p className="text-indigo-200 text-xs">Potenciado por Gemini</p>
              </div>
            </div>
          </div>

          {/* Messages */}
          <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50">
            {messages.map((msg) => (
              <div
                key={msg.id}
                className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}
              >
                <div
                  className={`max-w-[80%] p-3 rounded-2xl text-sm ${
                    msg.sender === 'user'
                      ? 'bg-indigo-600 text-white rounded-br-none'
                      : 'bg-white text-gray-700 shadow-sm border border-gray-100 rounded-bl-none'
                  }`}
                >
                  {msg.text}
                </div>
              </div>
            ))}
            {isLoading && (
              <div className="flex justify-start">
                <div className="bg-white p-3 rounded-2xl rounded-bl-none shadow-sm border border-gray-100 flex items-center space-x-2">
                  <Loader2 className="w-4 h-4 text-indigo-600 animate-spin" />
                  <span className="text-xs text-gray-500">Pensando...</span>
                </div>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>

          {/* Input */}
          <div className="p-4 bg-white border-t border-gray-100">
            <div className="flex items-center space-x-2">
              <input
                type="text"
                value={inputValue}
                onChange={(e) => setInputValue(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                placeholder="Ej. ¿Qué hay para niños hoy?"
                className="flex-1 p-2 bg-gray-100 rounded-full text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 border-none"
              />
              <button
                onClick={handleSend}
                disabled={isLoading || !inputValue.trim()}
                className="p-2 bg-indigo-600 rounded-full text-white hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
              >
                <Send className="w-4 h-4" />
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  );
};

