    // If array is empty, show all. If not empty, event must match one of the selected.
    const matchesCategory = selectedCategories.length === 0 || selectedCategories.includes(event.category);

    // 2. Search Filter
    const matchesSearch = event.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
                          event.category.toLowerCase().includes(searchQuery.toLowerCase());

    // 3. Date Filter
    let matchesDate = true;
    if (dateFilterStart) matchesDate = matchesDate && event.date >= dateFilterStart;
    if (dateFilterEnd) matchesDate = matchesDate && event.date <= dateFilterEnd;

    // 4. Time Filter
    let matchesTime = true;
    if (timeFilterStart) matchesTime = matchesTime && event.time >= timeFilterStart;
    if (timeFilterEnd) matchesTime = matchesTime && event.time <= timeFilterEnd;

    return matchesCategory && matchesSearch && matchesDate && matchesTime;
  }).sort((a, b) => a.date.localeCompare(b.date) || a.time.localeCompare(b.time));

