export const fetchEvents = async (): Promise<CulturalEvent[]> => {
    const url = `https://docs.google.com/spreadsheets/d/${SHEET_ID}/gviz/tq?tqx=out:json&sheet=${SHEET_NAME}`;

    try {
        const response = await fetch(url);
        if (!response.ok) {
            throw new Error(`Error HTTP: ${response.status}`);
        }

        const text = await response.text();

        // La API de visualización devuelve un JSONP con prefijo y sufijo.
        // Formato: /*O_o*/ google.visualization.Query.setResponse({ ... });
        // Usamos regex para extraer el JSON puro de forma segura.
        const match = text.match(/google\.visualization\.Query\.setResponse\(([\s\S]*)\)\;/);

        if (!match || !match[1]) {
           throw new Error("Formato de respuesta de Google Sheets no reconocido.");
        }

        const json = JSON.parse(match[1]);
        const rows = json.table.rows;

        if (!rows || rows.length === 0) return FALLBACK_EVENTS;

        // Mapeo de columnas según especificación:
        // A(0): titulo, B(1): categoria, C(2): fecha, D(3): hora, 
        // E(4): imagen, F(5): descripcion, G(6): lugar, H(7): link_mapa

        return rows.map((row: any, index: number) => {
            const c = row.c || [];

            // Función auxiliar para obtener valor
            const getVal = (i: number) => {
                const cell = c[i];
                if (!cell) return "";
                // Preferimos 'v' (valor) si es string simple, o 'f' (formateado) si es fecha/complejo
                return cell.v !== null ? String(cell.v) : "";
            };

            // Procesamiento especial para fechas (Col C / Index 2)
            // La API suele devolver "Date(yyyy,m,d)" en la propiedad 'v' si la celda es formato fecha
            let dateStr = getVal(2);
            const rawDate = c[2]?.v;

            if (typeof rawDate === 'string' && rawDate.indexOf('Date') !== -1) {
                // Parsear formato Date(2024,0,15) -> 2024-01-15
                const nums = rawDate.match(/\d+/g);
                if (nums && nums.length >= 3) {
                    const y = nums[0];
                    const m = String(Number(nums[1]) + 1).padStart(2, '0'); // Meses son 0-based
                    const d = String(nums[2]).padStart(2, '0');
                    dateStr = `${y}-${m}-${d}`;
                }
            }

            return {
                id: `sheet-${index}`,
                title: getVal(0),
                category: getVal(1),
                date: dateStr, 
                time: getVal(3), // Hora (String o formatted time)
                imageUrl: getVal(4),
                description: getVal(5),
                location: getVal(6),
                // Nota: Col H (7) link_mapa se omite ya que no existe en la interfaz CulturalEvent actual
                // pero se está leyendo del índice correcto si se necesitara.
            };
        });

    } catch (error) {
        console.error("Error cargando eventos desde Google Sheets:", error);
        // Retornamos fallback en caso de error para que la app no rompa
        return FALLBACK_EVENTS;
    }
};

